function fibonacci(n) {
  if (n <= 2) return 1;
  return fibonacci(n - 1) + fibonacci(n - 2);
}

console.log(fibonacci(10));  // console.logで '55' を表示

function hanoi(n, start, goal) {
  if (n === 1) {
    console.log(start + ' -> ' + goal);
    return;
  }
  const other = 6 - start - goal;
  hanoi(n - 1, start, other);
  console.log(start + ' -> ' + goal);
  hanoi(n - 1, other, goal);
}

hanoi(3, 1, 3);  // ディスクの移動手順が表示されます。

let memo = [];

function fibonacci(n) {
  if (n <= 2) return 1;
  if (memo[n]) return memo[n];  // すでに計算したことがある場合は、メモ化した値を返す
  memo[n] = fibonacci(n - 1) + fibonacci(n - 2);
  return memo[n];
}

console.log(fibonacci(10));  // console.logで '55' を表示

function generator() {
  let current = 1;
  return function() {
    let result = current;
    current++;
    return result;
  };
}

let gen = generator();

console.log(gen());  // 1
console.log(gen());  // 2
console.log(gen());  // 3

function doubleAfterOneSecond(x) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      const result = x * 2;
      console.log(result);  // console.logで結果を表示
      resolve(result);
    }, 1000);
  });
}

doubleAfterOneSecond(5).then(result => console.log('Promise returned: ', result));  // console.logで 'Promise returned:  10' を表示

function factorial(n) {
  if (n <= 1) return 1;  // nが1以下の場合は1を返す
  return n * factorial(n - 1);  // nと、n-1の階乗を掛けた結果を返す
}

console.log(factorial(5));  // console.logで '120' を表示

function createDoubleFunction() {
  // 引数の値を2倍にする関数を戻り値として返す
  return function(x) {
    return x * 2;
  };
}

const double = createDoubleFunction();
console.log(double(5));  // console.logで '10' を表示

let clickCount = 0;

function addClickListener() {
  document.addEventListener('click', () => {
    clickCount++;
    return clickCount;
  });
}

addClickListener();  // クリックする度にclickCountが増加し、その値が戻り値となる

function createCountFunction() {
  let count = 0;
  return function() {
    count++;
    return count;
  };
}

const countFunc = createCountFunction();
console.log(countFunc());  // 1
console.log(countFunc());  // 2

function asyncDouble(value) {
  return new Promise((resolve, reject) => {
    if(typeof value === 'number') {
      resolve(value * 2);
    } else {
      reject('Error: Value must be a number');
    }
  });
}

asyncDouble(5)
  .then(console.log)  // console.logで '10' を表示
  .catch(console.error);

function asyncProcess(value) {
  return new Promise((resolve, reject) => {
    if(typeof value === 'number') {
      resolve(value * 2);
    } else {
      reject(new Error('Value must be a number'));
    }
  });
}

asyncProcess('5')
  .then(console.log)
  .catch(error => console.log(error.message)); // Error: Value must be a number

function doubleValue(value) {
  return new Promise(resolve => resolve(value * 2));
}

doubleValue(5)
  .then(doubleValue)
  .then(doubleValue)
  .then(console.log);  // 20

async function doubleAfterSeconds(sec) {
  return new Promise(resolve => setTimeout(() => resolve(sec * 2), sec * 1000));
}

(async () => {
  const result = await doubleAfterSeconds(2);
  console.log(result);  // 4
})();

async function checkNumberAfterSeconds(sec) {
  return new Promise((resolve, reject) => setTimeout(() => {
    if(typeof sec === 'number') {
      resolve(sec * 2);
    } else {
      reject(new Error('Value must be a number'));
    }
  }, sec * 1000));
}

(async () => {
  try {
    const result = await checkNumberAfterSeconds('2');
    console.log(result);
  } catch (error) {
    console.log(error.message);  // Error: Value must be a number
  }
})();

async function doubleAfterSeconds(sec) {
  return new Promise(resolve => setTimeout(() => resolve(sec * 2), sec * 1000));
}

(async () => {
  const result = await Promise.all([doubleAfterSeconds(1), doubleAfterSeconds(2), doubleAfterSeconds(3)]);
  console.log(result);  // [2, 4, 6]
})();

async function doubleAfterSeconds(sec) {
  return new Promise(resolve => setTimeout(() => resolve(sec * 2), sec * 1000));
}

(async () => {
  const result = await Promise.race([doubleAfterSeconds(1), doubleAfterSeconds(2), doubleAfterSeconds(3)]);
  console.log(result);  // 2
})();

function* generatorFunction() {
  yield '1';
  yield '2';
  yield '3';
}

const generator = generatorFunction();

console.log(generator.next().value);  // '1'
console.log(generator.next().value);  // '2'
console.log(generator.next().value);  // '3'

async function multiplyNumbers(num) {
  return new Promise(resolve => {
    setTimeout(() => {
      resolve([num * 2, num * 3]);
    }, 1000);
  });
}

(async () => {
  const [result1, result2] = await multiplyNumbers(5);
  console.log(result1, result2);  // 10, 15
})();

function* powerOfTwo() {
  let result = 1;
  while (true) {
    yield result;
    result *= 2;
  }
}

let generator = powerOfTwo();
for (let i = 0; i < 5; i++) {
  console.log(generator.next().value);  // 1, 2, 4, 8, 16
}

async function multiplyNumbers(nums) {
  const promises = nums.map(num => {
    return new Promise(resolve => {
      setTimeout(() => {
        resolve(num * 2);
      }, 1000);
    });
  });
  return Promise.all(promises);
}

(async () => {
  const result = await multiplyNumbers([1, 2, 3, 4, 5]);
  console.log(result);  // [2, 4, 6, 8, 10]
})();
